import{_ as a,o as e,c as l,a7 as i}from"./chunks/framework.C5fSpjcB.js";const m=JSON.parse('{"title":"編成ガイド","description":"","frontmatter":{},"headers":[],"relativePath":"ja/awakeners/team-building.md","filePath":"ja/awakeners/team-building.md","lastUpdated":1775394001000}'),r={name:"ja/awakeners/team-building.md"};function s(n,t,d,o,h,c){return e(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="編成ガイド" tabindex="-1">編成ガイド <a class="header-anchor" href="#編成ガイド" aria-label="Permalink to &quot;編成ガイド&quot;">​</a></h1><p>忘却前夜の戦闘編成は<strong>最大4体</strong>の覚醒体で構成されます。界域シナジーや役割バランスを考慮して最適な編成を組みましょう。</p><h2 id="基本ルール" tabindex="-1">基本ルール <a class="header-anchor" href="#基本ルール" aria-label="Permalink to &quot;基本ルール&quot;">​</a></h2><ul><li>1編成に<strong>最大4体</strong>の覚醒体を配置可能</li><li>同一覚醒体の重複配置は不可</li><li>編成内の界域構成によりシナジーボーナスが発動</li></ul><h2 id="界域シナジー" tabindex="-1">界域シナジー <a class="header-anchor" href="#界域シナジー" aria-label="Permalink to &quot;界域シナジー&quot;">​</a></h2><p>同じ界域の覚醒体を複数編成することでシナジー効果が発動します。</p><table tabindex="0"><thead><tr><th style="text-align:center;">界域</th><th style="text-align:left;">2体</th><th style="text-align:left;">3体</th><th style="text-align:left;">4体（単色）</th></tr></thead><tbody><tr><td style="text-align:center;"><span class="realm-badge realm-chaos">混沌</span></td><td style="text-align:left;">狂気蓄積速度+15%</td><td style="text-align:left;">狂気蓄積速度+30%、バースト威力+10%</td><td style="text-align:left;">狂気蓄積速度+50%、バースト威力+25%</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-aequor">深海</span></td><td style="text-align:left;">シールド量+15%</td><td style="text-align:left;">シールド量+30%、回復効果+10%</td><td style="text-align:left;">シールド量+50%、回復効果+25%</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-caro">血肉</span></td><td style="text-align:left;">最大HP+15%</td><td style="text-align:left;">最大HP+30%、自傷ダメージ-10%</td><td style="text-align:left;">最大HP+50%、自傷ダメージ-25%</td></tr><tr><td style="text-align:center;"><span class="realm-badge realm-ultra">超維</span></td><td style="text-align:left;">算力回復+1</td><td style="text-align:left;">算力回復+1、ドロー+1</td><td style="text-align:left;">算力回復+2、ドロー+2</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>必ずしも単色編成が最強とは限りません。混合編成でも役割バランスが良ければ十分に戦えます。</p></div><h2 id="基本編成パターン" tabindex="-1">基本編成パターン <a class="header-anchor" href="#基本編成パターン" aria-label="Permalink to &quot;基本編成パターン&quot;">​</a></h2><h3 id="アタッカー重視型-2攻撃-1支援-1防御" tabindex="-1">アタッカー重視型（2攻撃+1支援+1防御） <a class="header-anchor" href="#アタッカー重視型-2攻撃-1支援-1防御" aria-label="Permalink to &quot;アタッカー重視型（2攻撃+1支援+1防御）&quot;">​</a></h3><p>速攻で敵を倒すことを目的とした編成。攻撃型を2体採用し、支援型のバフで火力を底上げします。</p><h3 id="バランス型-1攻撃-1支援-1防御-1妨害" tabindex="-1">バランス型（1攻撃+1支援+1防御+1妨害） <a class="header-anchor" href="#バランス型-1攻撃-1支援-1防御-1妨害" aria-label="Permalink to &quot;バランス型（1攻撃+1支援+1防御+1妨害）&quot;">​</a></h3><p>全役割を1体ずつ配置する安定型。あらゆるコンテンツに対応可能。</p><h3 id="コントロール型-1攻撃-2妨害-1支援" tabindex="-1">コントロール型（1攻撃+2妨害+1支援） <a class="header-anchor" href="#コントロール型-1攻撃-2妨害-1支援" aria-label="Permalink to &quot;コントロール型（1攻撃+2妨害+1支援）&quot;">​</a></h3><p>敵の行動を制限しながら戦う持久戦向け編成。相位対局（PvP）で有効。</p><h3 id="狂気バースト型-混沌3-自由枠1" tabindex="-1">狂気バースト型（混沌3+自由枠1） <a class="header-anchor" href="#狂気バースト型-混沌3-自由枠1" aria-label="Permalink to &quot;狂気バースト型（混沌3+自由枠1）&quot;">​</a></h3><p>混沌界域3体シナジーを活用し、狂気バーストの回転率で圧倒する編成。</p><h2 id="編成のコツ" tabindex="-1">編成のコツ <a class="header-anchor" href="#編成のコツ" aria-label="Permalink to &quot;編成のコツ&quot;">​</a></h2><ol><li><strong>算力管理を意識する</strong> — 毎ターン算力は5。高コストカードばかりだと手詰まりになる</li><li><strong>界域シナジーを活用する</strong> — 2体以上で発動するシナジーは強力</li><li><strong>狂気ゲージの管理</strong> — 100に達するとバーストが使用可能。意図的に溜める戦略も有効</li><li><strong>コンテンツに合わせて変更</strong> — 調査行動と相位対局では最適編成が異なる</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><span class="server-badge server-jp">JP</span> JPサーバーではバランス調整が他サーバーと異なる場合があります。CN/グローバル版のTier表をそのまま適用しないよう注意してください。</p></div><h2 id="コンテンツ別おすすめ編成" tabindex="-1">コンテンツ別おすすめ編成 <a class="header-anchor" href="#コンテンツ別おすすめ編成" aria-label="Permalink to &quot;コンテンツ別おすすめ編成&quot;">​</a></h2><h3 id="調査行動-investigation" tabindex="-1">調査行動（Investigation） <a class="header-anchor" href="#調査行動-investigation" aria-label="Permalink to &quot;調査行動（Investigation）&quot;">​</a></h3><p><em>準備中...</em></p><h3 id="相位対局-phase-chess-pvp" tabindex="-1">相位対局（Phase Chess / PvP） <a class="header-anchor" href="#相位対局-phase-chess-pvp" aria-label="Permalink to &quot;相位対局（Phase Chess / PvP）&quot;">​</a></h3><p><em>準備中...</em></p><h3 id="チャレンジステージ" tabindex="-1">チャレンジステージ <a class="header-anchor" href="#チャレンジステージ" aria-label="Permalink to &quot;チャレンジステージ&quot;">​</a></h3><p><em>準備中...</em></p><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">覚醒体図鑑</a></li><li><a href="./list.html">覚醒体一覧</a></li><li><a href="./../realms/">界域概要</a></li><li><a href="./../modes/combat.html">戦闘システム</a></li><li><a href="./../guides/tier-list.html">Tier表</a></li></ul>',29)])])}const g=a(r,[["render",s]]);export{m as __pageData,g as default};
